const RATE_TABLE = {
  house: [
    { min: 50, max: 120, rate: 5000 },
    { min: 120, max: 160, rate: 5500 },
    { min: 160, max: 220, rate: 6000 },
    { min: 220, max: 300, rate: 6500 },
    { min: 300, max: 400, rate: 7000 },
    { min: 400, max: 600, rate: 7500 },
    { min: 600, max: 1000, rate: 10000 },
  ],
  condo: [
    { min: 20, max: 25, rate: 2500 },
    { min: 26, max: 40, rate: 3000 },
    { min: 41, max: 50, rate: 3500 },
    { min: 51, max: 80, rate: 4000 },
    { min: 80, max: 100, rate: 5000 },
  ],
};

const calculateRate = (type, area) => {
  const table = RATE_TABLE[type];
  if (!table || !area) return null;
  const a = Number(area);
  for (const tier of table) {
    if (a >= tier.min && a <= tier.max) return tier.rate;
  }
  if (a > table[table.length - 1].max) return table[table.length - 1].rate;
  return null;
};

